      "content": "const express = require('express');
const router = express.Router({ mergeParams: true });
const { getTasksByStatus, updateTaskStatus } = require('./service');

router.get('/', async (req, res) => {
  const tasks = await getTasksByStatus(req.params.projectId, req.query.status);
  if (!tasks) return sendError(res, 404, 'E002', 'Tasks not found');
  res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const status = req.body.status;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'E003', 'Invalid task status');
  const updatedTask = await updateTaskStatus(req.params.projectId, req.params.taskId, status);
  res.json({ task: updatedTask });
});

exports.router = router;
